701: // enqueued on their shards or a shutdown signal is received.
702: func (t *QueueManager) Append(samples []record.RefSample) bool {
703: 	currentTime := time.Now()
704: outer:
705: 	for _, s := range samples {
706: 		if isSampleOld(currentTime, time.Duration(t.cfg.SampleAgeLimit), s.T) {
707: 			t.metrics.droppedSamplesTotal.WithLabelValues(reasonTooOld).Inc()
708: 			continue
709: 		}
710: 		t.seriesMtx.Lock()
711: 		lbls, ok := t.seriesLabels[s.Ref]
712: 		if !ok {
713: 			if _, ok := t.droppedSeries[s.Ref]; !ok {
714: 				t.logger.Info("Dropped sample for series that was not explicitly dropped via relabelling", "ref", s.Ref)
715: 				t.metrics.droppedSamplesTotal.WithLabelValues(reasonUnintentionalDroppedSeries).Inc()
716: 			} else {
717: 				t.metrics.droppedSamplesTotal.WithLabelValues(reasonDroppedSeries).Inc()
718: 			}
719: 			t.seriesMtx.Unlock()
720: 			continue
721: 		}
722: 		// TODO(cstyan): Handle or at least log an error if no metadata is found.
723: 		// See https://github.com/prometheus/prometheus/issues/14405
724: 		meta := t.seriesMetadata[s.Ref]
725: 		t.seriesMtx.Unlock()
726: 		// Start with a very small backoff. This should not be t.cfg.MinBackoff
727: 		// as it can happen without errors, and we want to pickup work after
728: 		// filling a queue/resharding as quickly as possible.
729: 		// TODO: Consider using the average duration of a request as the backoff.
730: 		backoff := model.Duration(5 * time.Millisecond)
731: 		for {
732: 			select {
733: 			case <-t.quit:
734: 				return false
735: 			default:
736: 			}
737: 			if t.shards.enqueue(s.Ref, timeSeries{
738: 				seriesLabels: lbls,
739: 				metadata:     meta,
740: 				timestamp:    s.T,
741: 				value:        s.V,
742: 				sType:        tSample,
743: 			}) {
744: 				continue outer
745: 			}
746: 
747: 			t.metrics.enqueueRetriesTotal.Inc()
748: 			time.Sleep(time.Duration(backoff))
749: 			backoff *= 2
750: 			// It is reasonable to use t.cfg.MaxBackoff here, as if we have hit
751: 			// the full backoff we are likely waiting for external resources.
752: 			if backoff > t.cfg.MaxBackoff {
753: 				backoff = t.cfg.MaxBackoff
754: 			}
755: 		}
756: 	}
757: 	return true
758: }
